    public Object parseOrderStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "part", "open" );
            put( "all", "closed" );
            put( "cancelled", "canceled" );
            put( "closed", "closed" );
            put( "no", "closed" );
        }};
        return this.safeString(statuses, status, status);
    }

    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        //     {
        //         "id":11,
        //         "datetime":"2014-10-21 10:47:21",
        //         "type":"sell",
        //         "price":42000,
        //         "amount_original":1.2,
        //         "amount_outstanding":1.2,
        //         "status":"closed",
        //         "trades":[] // no clarification of trade value structure of order endpoint
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(order, "id");
        Object datetimeString = this.safeString(order, "datetime");
        Object timestamp = null;
        if (Helpers.isTrue(!Helpers.isEqual(datetimeString, null)))
        {
            timestamp = this.parse8601(Helpers.add(Helpers.GetValue(order, "datetime"), "+09:00")); // Tokyo time
        }
        Object amount = this.safeString(order, "amount_original");
        Object remaining = this.safeString(order, "amount_outstanding");
        Object price = this.safeString(order, "price");
        // status is set by fetchOrder method only
        Object status = this.parseOrderStatus(this.safeString(order, "status"));
        // fetchOrders do not return status, use heuristic
        if (Helpers.isTrue(Helpers.isEqual(status, null)))
        {
            if (Helpers.isTrue(Precise.stringEquals(remaining, "0")))
            {
                status = "closed";
            }
        }
        Object trades = null; // todo: this.parseTrades (order['trades']);
        market = this.safeMarket(null, market);
        Object side = this.safeString(order, "type");
        final Object finalTimestamp = timestamp;
        final Object finalStatus = status;
        final Object finalMarket = market;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "clientOrderId", null );
            put( "timestamp", finalTimestamp );
            put( "datetime", BtcboxCore.this.iso8601(finalTimestamp) );
            put( "lastTradeTimestamp", null );
            put( "amount", amount );
            put( "remaining", remaining );
            put( "filled", null );
            put( "side", side );
            put( "type", null );
            put( "timeInForce", null );
            put( "postOnly", null );
            put( "status", finalStatus );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "price", price );
            put( "triggerPrice", null );
            put( "cost", null );
            put( "trades", trades );
            put( "fee", null );
            put( "info", order );
            put( "average", null );
        }}, market);
    }

