    public java.util.concurrent.CompletableFuture<Object> fetchOrdersByType(Object type2, Object... optionalArgs)
    {
        final Object type3 = type2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object type = type3;
            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            // a special case for btcbox – default symbol is BTC/JPY
            Object market = this.market(symbol);
            final Object finalType = type;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "type", finalType );
                put( "coin", Helpers.GetValue(market, "baseId") );
            }};
            Object response = (this.privatePostTradeList(this.extend(request, parameters))).join();
            //
            // [
            //      {
            //          "id":"7",
            //          "datetime":"2014-10-20 13:27:38",
            //          "type":"buy",
            //          "price":42750,
            //          "amount_original":0.235,
            //          "amount_outstanding":0.235
            //      },
            // ]
            //
            Object orders = this.parseOrders(response, market, since, limit);
            // status (open/closed/canceled) is undefined
            // btcbox does not return status, but we know it's 'open' as we queried for open orders
            if (Helpers.isTrue(Helpers.isEqual(type, "open")))
            {
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(orders)); i++)
                {
                    Helpers.addElementToObject(Helpers.GetValue(orders, i), "status", "open");
                }
            }
            return orders;
        });

    }

